import re
import math
import matplotlib.pyplot as plt

def parse_lds_data(log_str):
    # 正则匹配angle和distance(mm)
    pattern = r'angle:([\d\.]+),distance\(mm\):([\d]+)'
    matches = re.findall(pattern, log_str)
    points = []
    for angle_str, dist_str in matches:
        angle_deg = float(angle_str)
        dist_mm = int(dist_str)
        # 过滤距离为0的无效点
        if dist_mm <= 0:
            continue
        # 极坐标转直角坐标，单位米
        r = dist_mm / 1000.0
        rad = math.radians(angle_deg)
        x = r * math.cos(rad)
        y = r * math.sin(rad)
        points.append((x, y))
    return points

